def verify_signature(payload: bytes, signature: str, secret: str, algorithm: str = 'sha256') -> bool:
    """Verify HMAC signature of the webhook payload"""
    if not signature or not secret:
        return False
    
    try:
        expected_signature = hmac.new(
            secret.encode('utf-8'),
            payload,
            hashlib.sha256
        ).hexdigest()
        
        # Constant-time comparison to prevent timing attacks
        return hmac.compare_digest(signature, expected_signature)
    except Exception as e:
        logger.error(f"Signature verification error: {type(e).__name__}")
        return False


def verify_timestamp(timestamp: Optional[str]) -> bool:
    """Verify timestamp to prevent replay attacks"""
    if not timestamp:
        return False
    
    try:
        webhook_time = datetime.fromisoformat(timestamp.replace('Z', '+00:00'))
        current_time = datetime.utcnow()
        time_diff = abs((current_time - webhook_time).total_seconds())
        
        return time_diff <= TIMESTAMP_TOLERANCE_SECONDS
    except Exception as e:
        logger.error(f"Timestamp verification error: {type(e).__name__}")
        return False


def sanitize_log_data(data: Dict[str, Any]) -> Dict[str, Any]:
    """Remove sensitive fields from data before logging"""
    sensitive_fields = {
        'card_number', 'cvv', 'ssn', 'password', 'token', 'secret',
        'api_key', 'authorization', 'credit_card', 'account_number',
        'routing_number', 'pin', 'security_code'
    }
    
    sanitized = {}
    for key, value in data.items():
        key_lower = key.lower()
        if any(sensitive in key_lower for sensitive in sensitive_fields):
            sanitized[key] = '[REDACTED]'
        elif isinstance(value, dict):
            sanitized[key] = sanitize_log_data(value)
        elif isinstance(value, list):
            sanitized[key] = [sanitize_log_data(item) if isinstance(item, dict) else item for item in value]
        else:
            sanitized[key] = value
    
    return sanitized


